#include <assert.h>
#include <string.h>
#include <stdlib.h>
#include "../cJSON.h"

void test_create_object(void) {
    cJSON *obj = cJSON_CreateObject();
    assert(obj != NULL);
    assert(cJSON_IsObject(obj));
    cJSON_Delete(obj);
}

void test_add_string(void) {
    cJSON *obj = cJSON_CreateObject();
    cJSON_AddStringToObject(obj, "name", "test");
    cJSON *item = cJSON_GetObjectItem(obj, "name");
    assert(item != NULL);
    assert(strcmp(item->valuestring, "test") == 0);
    cJSON_Delete(obj);
}

void test_print_json(void) {
    cJSON *obj = cJSON_CreateObject();
    cJSON_AddStringToObject(obj, "key", "value");
    char *json = cJSON_Print(obj);
    assert(json != NULL);
    assert(strstr(json, "key") != NULL);
    assert(strstr(json, "value") != NULL);
    free(json);
    cJSON_Delete(obj);
}

int main(void) {
    test_create_object();
    test_add_string();
    test_print_json();
    printf("All cJSON tests passed!\n");
    return 0;
}

CJSON_PUBLIC(int) cJSON_GetObjectItemCount(const cJSON *object)
{
    int count = 0;
    cJSON *current;
    if (object == NULL || !cJSON_IsObject(object))
    {
        return -1;
    }
    current = object->child;
    while (current != NULL)
    {
        count++;
        current = current->next;
    }
    return count;
}
